
.info-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 6px 16px;
  margin-bottom: 8px;
}

.info-item {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
  padding: 3px 0;
  border-bottom: 1px dotted rgba(139, 90, 43, 0.15);
}

.info-key {
  font-size: 11px;
  color: #7a5c4a;
}

.info-val {
  font-size: 12px;
  font-weight: 600;
  color: #2c1810;
  text-align: right;

  &.name { color: #2c1810; }
  &.balance { color: #b8860b; }
}

.section {
  margin-top: 8px;
}

.section-title {
  font-size: 10px;
  color: #7a5c4a;
  margin-bottom: 4px;
  font-style: italic;
}

.item-list {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
}

.item-tag {
  display: inline-block;
  padding: 2px 8px;
  background: rgba(139, 90, 43, 0.08);
  border: 1px solid rgba(139, 90, 43, 0.15);
  border-radius: 2px;
  font-size: 11px;
  color: #4a3020;
}

.card-tag {
  background: rgba(139, 69, 19, 0.1);
  border-color: rgba(139, 69, 19, 0.2);
  color: #6b3a1f;
}

.empty {
  text-align: center;
  color: #7a5c4a;
  font-size: 12px;
  font-style: italic;
  padding: 8px 0;
}
