
.char-row {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 4px 0;
  border-bottom: 1px dotted rgba(139, 90, 43, 0.1);

  &:last-child { border-bottom: none; }
}

.char-name {
  width: 64px;
  font-size: 12px;
  font-weight: 600;
  color: #2c1810;
  flex-shrink: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.char-bar-wrap { flex: 1; }

.char-bar {
  height: 5px;
  background: rgba(139, 90, 43, 0.1);
  border-radius: 3px;
  overflow: hidden;
}

.char-fill {
  height: 100%;
  border-radius: 3px;
  transition: width 0.8s ease;
}

.char-val {
  width: 32px;
  font-size: 12px;
  font-weight: 700;
  text-align: right;
  flex-shrink: 0;
  font-variant-numeric: tabular-nums;
}

.char-rel {
  width: 40px;
  font-size: 10px;
  text-align: right;
  flex-shrink: 0;
  font-style: italic;
}

.empty {
  text-align: center;
  color: #7a5c4a;
  font-size: 12px;
  font-style: italic;
  padding: 12px 0;
}
