
.info-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 6px 16px;
}

.info-item {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
  padding: 3px 0;
  border-bottom: 1px dotted rgba(139, 90, 43, 0.15);

  &.wide {
    grid-column: 1 / -1;
  }
}

.info-key {
  font-size: 11px;
  color: #7a5c4a;
  flex-shrink: 0;
}

.info-val {
  font-size: 12px;
  font-weight: 600;
  color: #2c1810;
  text-align: right;

  &.season { color: #5b8c3e; }
  &.weather { color: #b8860b; }
  &.location { color: #6b4d3a; }
  &.volume { color: #8b4513; font-style: italic; }
}
